{
  "global": "Determine the total uncertainty of the sample mean μ̂ when both Type A (random measurement) and Type B (instrument scale quantization) errors are present.",
  "subtasks": [
    {
      "subtask": "Establish Type A uncertainty from random measurement variability",
      "atomics": [
        "Recognize that sample mean μ̂ = (1/N)ΣXᵢ follows Gaussian distribution with mean μ and standard deviation s/√N",
        "Define Type A uncertainty as σ_A = s/√N"
      ]
    },
    {
      "subtask": "Characterize the uniform scale quantization error XB",
      "atomics": [
        "Model XB as uniform random variable on interval [-a/2, a/2]",
        "Calculate variance of uniform distribution: Var(XB) = (a - (-a))²/12 = a²/12",
        "Calculate standard deviation: SD(XB) = √(a²/12) = a/(2√3)"
      ]
    },
    {
      "subtask": "Analyze the effect of XB on the mean estimate",
      "atomics": [
        "Recognize that μ̂' = (1/N)Σ(Xᵢ + XB) = μ̂ + XB when scale error is added to each measurement",
        "Observe that XB affects all N measurements equally, so it does not average out",
        "Conclude that Type B uncertainty contribution is σ_B = a/(2√3) without √N factor"
      ]
    },
    {
      "subtask": "Combine Type A and Type B uncertainties",
      "atomics": [
        "Recognize Type A and Type B as independent error sources",
        "Apply quadrature formula for independent uncertainties: σ_total = √(σ_A² + σ_B²)",
        "Substitute components: σ_total = √((s/√N)² + (a/(2√3))²)",
        "Simplify: σ_total = √(s²/N + a²/12)"
      ]
    }
  ],
  "global_atomics": [
    "Verify dimensional consistency: all terms have dimension of measured quantity [X]",
    "Verify limiting case: as a → 0, total uncertainty reduces to Type A only: s/√N"
  ],
  "gold_actions": {
    "global": "Calculate the combined measurement uncertainty of μ̂ by combining Type A random error (s/√N) with Type B scale quantization error (a/(2√3)) in quadrature.",
    "subtasks": [
      {
        "subtask": "Establish Type A standard error of the mean",
        "atomics": [
          "State that μ̂ ~ Gaussian(μ, s/√N) by central limit theorem",
          "Define σ_A = s/√N as Type A uncertainty"
        ]
      },
      {
        "subtask": "Determine the variance and standard deviation of uniform scale error",
        "atomics": [
          "Compute Var(XB) = a²/12 for XB ~ Uniform[-a/2, a/2]",
          "Extract SD(XB) = a/(2√3) = a/√12"
        ]
      },
      {
        "subtask": "Recognize how systematic scale error propagates to mean estimate",
        "atomics": [
          "Show μ̂' = μ̂ + XB when constant error XB is added to all measurements",
          "Establish that σ_B = a/(2√3) without division by √N (common offset)"
        ]
      },
      {
        "subtask": "Combine independent uncertainties in quadrature",
        "atomics": [
          "Apply σ_total² = σ_A² + σ_B² = (s/√N)² + (a/(2√3))²",
          "Compute σ_total = √(s²/N + a²/12)"
        ]
      }
    ],
    "global_atomics": [
      "Confirm result has correct dimension [X]",
      "Verify a → 0 limit recovers σ_total = s/√N"
    ]
  }
}
```
